import React, { useState } from 'react'
import { Avatar, Button, Input } from 'antd'
import { UserOutlined, EyeTwoTone, EyeInvisibleOutlined, ArrowLeftOutlined } from '@ant-design/icons'
import './index.css'

export default function Register() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [usernameError, setUsernameError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [isRegistered, setIsRegistered] = useState(false);



  // 提交事件
  const handleRegister = async () => {
    try {
      const response = await fetch('http://localhost:4000/api/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ username, password }),
      });

      if (response.ok) {
        // 注册成功，可以进行重定向或显示成功消息
        console.log('注册成功！');
        setIsRegistered(true)
      } else {
        const data = await response.json();
        if (data.error.includes('用户名已存在')) {
          setUsernameError('您的用户名已经有人注册！');
        } else if (data.error.includes('密码必须')) {
          setPasswordError('密码必须8位以上');
        }
        // 注册失败，处理错误情况
        console.error('注册失败！');
      }
    } catch (error) {
      console.error('发生错误：', error);
    }
  };

  // 键盘敲击事件
  const handleEnterKey = (event) => {
    if (event.key === 'Enter') {
      setUsername('');
      setPassword('');

      if (password.length > 8) {
        handleRegister();
      } else {
        setPasswordError("密码必须8位以上！！！")
      }
    }
  }
  return (
    <div className='register'>
      <Avatar
        size={100}
      />
      <Input
        size='large'
        placeholder='input id'
        style={{
          width: '200px',
          marginBottom: "20px",
          marginTop: "30px"
        }}
        suffix={<UserOutlined />}
      ></Input>
      <Input.Password
        size='large'
        placeholder="input password"
        style={{
          width: '200px',
        }}
        prefix={(visible) => (visible ? <EyeTwoTone /> : <EyeInvisibleOutlined />)}
        onClick={handleEnterKey}
      />
      <Button ghost style={{ marginTop: '20px' }} >Register</Button>
      <Button
        style={{ marginTop: '170px' }}
        type='link'
        href='/login'
      ><ArrowLeftOutlined />Login</Button>
    </div>
  )
}
